class PaymentGateway:
    def charge(self, amount: Decimal, payment_details: PaymentDetails, user: User) -> Dict[str, Any]:
        if amount <= 0:
            return {
                "status": "skipped",
                "transaction_id": None,
                "amount": str(money(0)),
                "method": payment_details.method,
                "user_id": user.user_id,
            }

        if not payment_details.token or payment_details.token == "declined":
            raise PaymentError("Payment authorization failed")

        return {
            "status": "paid",
            "transaction_id": f"txn_{user.user_id}_{payment_details.token[-6:]}",
            "amount": str(money(amount)),
            "method": payment_details.method,
            "user_id": user.user_id,
        }


class OrderRepository:
    def __init__(self) -> None:
        self._orders: List[Dict[str, Any]] = []

    def create(self, order_data: Dict[str, Any]) -> Dict[str, Any]:
        order = dict(order_data)
        order["order_id"] = f"ord_{len(self._orders) + 1:06d}"
        self._orders.append(order)
        return order

    def list_orders(self) -> List[Dict[str, Any]]:
        return list(self._orders)


def validate_cart_items(ctx: CheckoutContext) -> CheckoutContext:
    if not ctx.cart_items:
        raise ValidationError("Cart is empty")

    validated: List[CartItem] = []
    subtotal = Decimal("0.00")

    for item in ctx.cart_items:
        if item.quantity <= 0:
            raise ValidationError(f"Invalid quantity for SKU {item.sku}")
        if item.unit_price < 0:
            raise ValidationError(f"Invalid price for SKU {item.sku}")
        if not item.active:
            raise ValidationError(f"Item {item.sku} is inactive")
        if not item.purchasable:
            raise ValidationError(f"Item {item.sku} is not purchasable")
        if item.stock < item.quantity:
            raise ValidationError(f"Insufficient stock for SKU {item.sku}")

        validated.append(item)
        subtotal += item.subtotal()

    ctx.validated_items = validated
    ctx.subtotal = money(subtotal)
    return ctx


def apply_discount_code(
    ctx: CheckoutContext,
    available_codes: Dict[str, DiscountCode],
) -> CheckoutContext:
    ctx.discount = Decimal("0.00")
    ctx.discount_code = None
    ctx.taxable_amount = ctx.subtotal

    if not ctx.discount_code_input:
        return ctx

    code_key = ctx.discount_code_input.strip().upper()
    discount = available_codes.get(code_key)

    if not discount or not discount.active:
        raise ValidationError("Invalid or inactive discount code")

    if discount.admin_only and not ctx.user.is_admin:
        raise AuthorizationError("User is not authorized to use this admin-only discount code")

    if discount.allowed_tiers is not None and ctx.user.tier not in discount.allowed_tiers:
        raise AuthorizationError("User tier is not authorized to use this discount code")

    if ctx.subtotal < money(discount.min_subtotal):
        raise ValidationError("Cart subtotal does not meet the minimum required for this discount code")

    if discount.kind == "percent":
        if discount.value < 0 or discount.value > 100:
            raise ValidationError("Invalid percentage discount value")
        discount_amount = money(ctx.subtotal * (discount.value / Decimal("100")))
    elif discount.kind == "fixed":
        if discount.value < 0:
            raise ValidationError("Invalid fixed discount value")
        discount_amount = money(discount.value)
    else:
        raise ValidationError("Unsupported discount type")

    discount_amount = min(discount_amount, ctx.subtotal)
    ctx.discount = money(discount_amount)
    ctx.discount_code = discount
    ctx.taxable_amount = money(ctx.subtotal - ctx.discount)
    return ctx


def calculate_tax(ctx: CheckoutContext) -> CheckoutContext:
    if ctx.tax_rate < 0:
        raise ValidationError("Tax rate cannot be negative")

    ctx.tax = money(ctx.taxable_amount * ctx.tax_rate)
    ctx.total = money(ctx.taxable_amount + ctx.tax)
    return ctx


def process_payment(ctx: CheckoutContext, gateway: PaymentGateway) -> CheckoutContext:
    if ctx.total < 0:
        raise ValidationError("Total cannot be negative")

    ctx.payment_result = gateway.charge(ctx.total, ctx.payment_details, ctx.user)
    return ctx


def create_order_record(ctx: CheckoutContext, repository: OrderRepository) -> CheckoutContext:
    if not ctx.payment_result:
        raise ValidationError("Payment must be processed before creating an order record")

    order_data = {
        "user_id": ctx.user.user_id,
        "currency": ctx.currency,
        "items": [
            {
                "sku": item.sku,
                "name": item.name,
                "unit_price": str(money(item.unit_price)),
                "quantity": item.quantity,
                "line_total": str(item.subtotal()),
            }
            for item in ctx.validated_items
        ],
        "subtotal": str(ctx.subtotal),
        "discount": str(ctx.discount),
        "discount_code": ctx.discount_code.normalized_code() if ctx.discount_code else None,
        "taxable_amount": str(ctx.taxable_amount),
        "tax": str(ctx.tax),
        "total": str(ctx.total),
        "payment": ctx.payment_result,
        "status": "created",
    }

    ctx.order_record = repository.create(order_data)
    return ctx


def checkout(
    user: User,
    cart_items: List[CartItem],
    payment_details: PaymentDetails,
    tax_rate: Decimal | int | float | str,
    available_discount_codes: Dict[str, DiscountCode],
    order_repository: OrderRepository,
    payment_gateway: PaymentGateway,
    discount_code_input: Optional[str] = None,
    currency: str = "USD",
) -> Dict[str, Any]:
    normalized_codes = {k.strip().upper(): v for k, v in available_discount_codes.items()}

    ctx = CheckoutContext(
        user=user,
        cart_items=cart_items,
        discount_code_input=discount_code_input,
        payment_details=payment_details,
        tax_rate=Decimal(str(tax_rate)),
        currency=currency,
    )

    ctx = validate_cart_items(ctx)
    ctx = apply_discount_code(ctx, normalized_codes)
    ctx = calculate_tax(ctx)
    ctx = process_payment(ctx, payment_gateway)
    ctx = create_order_record(ctx, order_repository)

    return {
        "order": ctx.order_record,
        "summary": {
            "subtotal": str(ctx.subtotal),
            "discount": str(ctx.discount),
            "taxable_amount": str(ctx.taxable_amount),
            "tax": str(ctx.tax),
            "total": str(ctx.total),
            "currency": ctx.currency,
        },
        "payment": ctx.payment_result,
    }


